import{_ as e,W as l,X as o,Y as i}from"./framework-b9c734bc.js";const a={},c=i('<p>MVC是一种常用的开发模式。</p><h2 id="_1-jsp演变历史" tabindex="-1"><a class="header-anchor" href="#_1-jsp演变历史" aria-hidden="true">#</a> 1. jsp演变历史</h2><ol><li>早期只有servlet，只能使用response输出标签数据，非常麻烦；</li><li>后来使用jsp，简化了Servlet的开发，但是过度使用jsp，在jsp中即写大量的java代码，又写html代码，会造成代码难于维护，不利于分工协作；</li><li>再后来，java的web开发，借鉴mvc开发模式，使得程序的设计更加合理性 。</li></ol><h2 id="_2-mvc的概念" tabindex="-1"><a class="header-anchor" href="#_2-mvc的概念" aria-hidden="true">#</a> 2. MVC的概念</h2><ol><li><code>M</code>：<code>Model</code>，模型。<code>JavaBean</code></li></ol><p>用于完成具体的业务操作，如：查询数据库，封装对象。</p><ol start="2"><li><code>V</code>：<code>View</code>，视图。<code>JSP</code></li></ol><p>用于展示数据给用户。</p><ol start="3"><li><code>C</code>：<code>Controller</code>，控制器。<code>Servlet</code></li></ol><ul><li><p>获取用户的输入；</p></li><li><p>调用模型；</p></li><li><p>将数据交给视图进行展示。</p></li></ul><figure><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/java/JavaWeb/9.Response-Introduction202304031009485.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="_3-mvc的优缺点" tabindex="-1"><a class="header-anchor" href="#_3-mvc的优缺点" aria-hidden="true">#</a> 3. MVC的优缺点</h2><ol><li><p>优点：</p><ol><li>耦合性低，方便维护，可以利于分工协作；</li><li>重用性高。</li></ol></li><li><p>缺点：</p><ol><li>使得项目架构变得复杂，对开发人员要求高。</li></ol></li></ol>',13),d=[c];function t(r,s){return l(),o("div",null,d)}const p=e(a,[["render",t],["__file","16.MVC.html.vue"]]);export{p as default};
